const rawText = $json.body.content[0].text;

const cleanedText = rawText
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/```$/i, '')
  .trim();

let parsed;

try {
  parsed = JSON.parse(cleanedText);
} catch (error) {
  throw new Error(`Could not parse Claude JSON: ${error.message}`);
}

return [
  {
    json: {
      caption: parsed.caption,
      hashtags: parsed.hashtags,
      instagramAltText: parsed.instagramAltText,
    },
  },
];

// n8n Code node: Parse & Rank SEO Keyword Data
// Place directly after your DataForSEO HTTP Request node.
// Designed for seo_blog input like:
// content.title, content.excerpt, content.body_markdown, content.tags

function unwrapDataForSEOResponse(inputJson) {
  let data = inputJson;

  if (data && data.body !== undefined) {
    data = data.body;
  }

  if (typeof data === "string") {
    try {
      data = JSON.parse(data);
    } catch (error) {
      throw new Error("DataForSEO response body is a string but not valid JSON.");
    }
  }

  if (Array.isArray(data)) {
    data = data[0];
  }

  return data;
}

function cleanText(value) {
  return String(value ?? "")
    .toLowerCase()
    .replace(/\s+/g, " ")
    .trim();
}

function titleCaseKeyword(value) {
  return String(value ?? "")
    .replace(/\s+/g, " ")
    .trim();
}

function isRepeatedLocationKeyword(keyword) {
  const k = cleanText(keyword);
  return k === "sydney sydney";
}

function isTooBroad(keyword) {
  const k = cleanText(keyword);

  const broadKeywords = [
    "sydney",
    "luxury",
    "renovation"
  ];

  return broadKeywords.includes(k);
}

function hasCommercialOrLocalIntent(keyword) {
  const k = cleanText(keyword);

  const intentTerms = [
    "renovation",
    "renovations",
    "home",
    "homes",
    "builder",
    "company",
    "design",
    "kitchen",
    "bathroom",
    "luxury"
  ];

  const locationTerms = [
    "sydney",
    "new south wales",
    "nsw"
  ];

  return (
    intentTerms.some(term => k.includes(term)) &&
    locationTerms.some(term => k.includes(term))
  );
}

function isBlogTopicKeyword(keyword) {
  const k = cleanText(keyword);

  const blogTerms = [
    "trend",
    "trends",
    "ideas",
    "design",
    "modern",
    "2026"
  ];

  return blogTerms.some(term => k.includes(term));
}

function calculateSeoScore(item) {
  const keyword = cleanText(item.keyword);
  const volume = Number(item.searchVolume || 0);
  const cpc = Number(item.cpc || 0);
  const competitionIndex =
    typeof item.competitionIndex === "number"
      ? item.competitionIndex
      : 50;

  let score = 0;

  // Volume helps, but avoid letting "sydney" dominate.
  score += Math.log10(volume + 1) * 20;

  // CPC indicates commercial value.
  score += Math.min(cpc, 25) * 2;

  // Reward relevant local/commercial phrases.
  if (hasCommercialOrLocalIntent(keyword)) score += 60;

  // Reward blog/topic relevance.
  if (isBlogTopicKeyword(keyword)) score += 25;

  // Reward stronger renovation terms.
  if (keyword.includes("home renovation") || keyword.includes("home renovations")) score += 35;
  if (keyword.includes("luxury renovation") || keyword.includes("luxury renovations")) score += 25;
  if (keyword.includes("renovation sydney") || keyword.includes("renovations sydney")) score += 25;
  if (keyword.includes("renovation company")) score += 20;

  // Medium competition is okay; extreme generic/high competition is less ideal.
  if (competitionIndex >= 30 && competitionIndex <= 70) score += 10;
  if (competitionIndex > 80) score -= 10;

  // Penalize broad or weird keywords.
  if (isTooBroad(keyword)) score -= 100;
  if (isRepeatedLocationKeyword(keyword)) score -= 100;
  if (keyword.split(" ").length === 1) score -= 50;

  return Math.round(score * 100) / 100;
}

const inputItems = $input.all();

if (!inputItems.length) {
  throw new Error("No input received from DataForSEO node.");
}

const response = unwrapDataForSEOResponse(inputItems[0].json);

if (!response) {
  throw new Error("No DataForSEO response found.");
}

if (response.status_code !== 20000) {
  throw new Error(
    `DataForSEO API error: ${response.status_code || "unknown"} - ${response.status_message || "No message"}`
  );
}

const tasks = response.tasks || [];

if (!tasks.length) {
  throw new Error("DataForSEO response has no tasks.");
}

const task = tasks[0];

if (task.status_code !== 20000) {
  throw new Error(
    `DataForSEO task error: ${task.status_code || "unknown"} - ${task.status_message || "No message"}`
  );
}

const rawResults = task.result || [];
const seedKeywords = Array.isArray(task.data?.keywords) ? task.data.keywords : [];

if (!rawResults.length) {
  return [
    {
      json: {
        primaryKeyword: "home renovations sydney",
        secondaryKeywords: [
          "renovation sydney",
          "luxury renovations sydney",
          "home renovation trends 2026"
        ],
        localCommercialKeywords: [],
        blogTopicKeywords: seedKeywords,
        topKeywords: [],
        keywordSummary: "No keyword results returned from DataForSEO.",
        keywordQuality: "no_results",
        usableKeywordCount: 0,
        totalKeywordCount: 0,
        needsMoreKeywordResearch: true,
        recommendedAction: "Run another keyword research request with more service-specific keywords.",
        dataforseoCost: response.cost || task.cost || 0,
        dataforseoTaskId: task.id || "",
        locationName: task.data?.location_name || "",
        languageCode: task.data?.language_code || "",
        campaignTag: task.data?.tag || "",
        processedAt: new Date().toISOString()
      }
    }
  ];
}

const seen = new Set();

const allKeywords = rawResults
  .filter(item => item && item.keyword)
  .map(item => {
    const normalizedKeyword = cleanText(item.spell || item.keyword);
    const displayKeyword = titleCaseKeyword(item.spell || item.keyword);

    const searchVolume =
      typeof item.search_volume === "number"
        ? item.search_volume
        : 0;

    const cpc =
      typeof item.cpc === "number"
        ? item.cpc
        : null;

    const competition =
      item.competition !== null && item.competition !== undefined
        ? item.competition
        : "N/A";

    const competitionIndex =
      typeof item.competition_index === "number"
        ? item.competition_index
        : null;

    const monthlySearches = Array.isArray(item.monthly_searches)
      ? item.monthly_searches
      : [];

    const latestTrend = monthlySearches
      .slice(0, 3)
      .map(month => {
        const year = month.year || "";
        const monthNumber = String(month.month || "").padStart(2, "0");
        const volume = month.search_volume || 0;
        return `${year}-${monthNumber}: ${volume}`;
      })
      .join(", ");

    return {
      keyword: normalizedKeyword,
      displayKeyword,
      originalKeyword: item.keyword,
      searchVolume,
      competition,
      competitionIndex,
      cpc,
      lowTopOfPageBid:
        typeof item.low_top_of_page_bid === "number"
          ? item.low_top_of_page_bid
          : null,
      highTopOfPageBid:
        typeof item.high_top_of_page_bid === "number"
          ? item.high_top_of_page_bid
          : null,
      latestTrend,
      monthlySearches,
      isTooBroad: isTooBroad(normalizedKeyword),
      isRepeatedLocationKeyword: isRepeatedLocationKeyword(normalizedKeyword),
      hasLocalCommercialIntent: hasCommercialOrLocalIntent(normalizedKeyword),
      isBlogTopicKeyword: isBlogTopicKeyword(normalizedKeyword)
    };
  })
  .filter(item => {
    if (!item.keyword) return false;
    if (seen.has(item.keyword)) return false;
    seen.add(item.keyword);
    return true;
  })
  .map(item => ({
    ...item,
    seoScore: calculateSeoScore(item)
  }));

const usableKeywords = allKeywords.filter(item => item.searchVolume > 0);

const rankedKeywords = [...allKeywords].sort((a, b) => {
  if (b.seoScore !== a.seoScore) return b.seoScore - a.seoScore;
  if (b.searchVolume !== a.searchVolume) return b.searchVolume - a.searchVolume;

  const aCpc = a.cpc || 0;
  const bCpc = b.cpc || 0;
  return bCpc - aCpc;
});

const primaryCandidates = rankedKeywords.filter(item => {
  return (
    !item.isTooBroad &&
    !item.isRepeatedLocationKeyword &&
    item.hasLocalCommercialIntent &&
    item.searchVolume > 0
  );
});

const primaryKeyword =
  primaryCandidates[0]?.keyword ||
  rankedKeywords.find(item => !item.isTooBroad && !item.isRepeatedLocationKeyword)?.keyword ||
  "home renovations sydney";

const topKeywords = rankedKeywords
  .filter(item => !item.isRepeatedLocationKeyword)
  .slice(0, 10);

const secondaryKeywords = rankedKeywords
  .filter(item => item.keyword !== primaryKeyword)
  .filter(item => !item.isTooBroad)
  .filter(item => !item.isRepeatedLocationKeyword)
  .slice(0, 8)
  .map(item => item.keyword);

const localCommercialKeywords = rankedKeywords
  .filter(item => item.hasLocalCommercialIntent)
  .filter(item => !item.isTooBroad)
  .filter(item => !item.isRepeatedLocationKeyword)
  .slice(0, 8)
  .map(item => ({
    keyword: item.keyword,
    searchVolume: item.searchVolume,
    cpc: item.cpc,
    competition: item.competition,
    seoScore: item.seoScore
  }));

const blogTopicKeywords = rankedKeywords
  .filter(item => item.isBlogTopicKeyword)
  .filter(item => !item.isRepeatedLocationKeyword)
  .slice(0, 8)
  .map(item => ({
    keyword: item.keyword,
    searchVolume: item.searchVolume,
    competition: item.competition,
    seoScore: item.seoScore
  }));

const keywordSummary = topKeywords.length
  ? topKeywords
      .map(k => {
        const volume = k.searchVolume || 0;
        const cpc = k.cpc !== null ? `$${Number(k.cpc).toFixed(2)}` : "N/A";
        const competition = k.competition || "N/A";
        return `${k.keyword} (Vol: ${volume}, CPC: ${cpc}, Competition: ${competition}, SEO Score: ${k.seoScore})`;
      })
      .join(" | ")
  : `${primaryKeyword} (Vol: 0, CPC: N/A, Competition: N/A)`;

let keywordQuality = "weak";

if (localCommercialKeywords.length >= 3 && usableKeywords.length >= 5) {
  keywordQuality = "good";
} else if (localCommercialKeywords.length >= 1 || usableKeywords.length >= 3) {
  keywordQuality = "usable";
}

const recommendedArticleFocus = {
  seoTitle: `Top Home Renovation Trends in Sydney for 2026`,
  primaryKeyword,
  suggestedH1: `Top Home Renovation Trends in Sydney for 2026`,
  suggestedMetaDescription:
    "Explore the top home renovation trends in Sydney for 2026, including luxury design ideas, natural lighting, modern finishes, and smart renovation planning.",
  recommendedUrlSlug: "home-renovation-trends-sydney-2026"
};

return [
  {
    json: {
      primaryKeyword,
      secondaryKeywords,
      localCommercialKeywords,
      blogTopicKeywords,
      topKeywords,

      keywordSummary,
      keywordQuality,

      usableKeywordCount: usableKeywords.length,
      totalKeywordCount: allKeywords.length,
      needsMoreKeywordResearch: localCommercialKeywords.length < 3,

      recommendedArticleFocus,

      suggestedFallbackKeywords: [
        "home renovations sydney",
        "home renovation sydney",
        "renovation builder sydney",
        "renovation company sydney",
        "kitchen renovation sydney",
        "bathroom renovation sydney",
        "custom home renovations sydney",
        "luxury home renovations sydney",
        "house renovation sydney",
        "home improvement sydney"
      ],

      excludedNotes: [
        "Broad terms like 'sydney', 'luxury', and 'renovation' are not used as primary keywords even if they have high search volume.",
        "Repeated-location keywords like 'sydney sydney' are excluded from ranking."
      ],

      dataforseoCost: response.cost || task.cost || 0,
      dataforseoTaskId: task.id || "",
      locationName: task.data?.location_name || "",
      languageCode: task.data?.language_code || "",
      campaignTag: task.data?.tag || "",

      rawKeywordCount: rawResults.length,
      processedAt: new Date().toISOString()
    }
  }
];

const item = $input.first();

let text =
  item.json.text ||
  item.json.output ||
  item.json.response ||
  item.json.content?.[0]?.text ||
  item.json.message?.content ||
  '';

if (Array.isArray(item.json.message?.content)) {
  text = item.json.message.content.map(part => part.text || '').join('\n');
}

if (!text) {
  text = JSON.stringify(item.json);
}

text = String(text).trim();

// Remove markdown code fences
text = text
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '')
  .trim();

// Extract JSON object
const firstBrace = text.indexOf('{');
const lastBrace = text.lastIndexOf('}');

if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
  throw new Error('No valid JSON object found in Claude response.');
}

text = text.slice(firstBrace, lastBrace + 1);

let data;

try {
  data = JSON.parse(text);
} catch (error) {
  throw new Error(
    'Claude did not return valid JSON: ' +
    error.message +
    '\nStart preview: ' +
    text.slice(0, 500) +
    '\nEnd preview: ' +
    text.slice(-500)
  );
}

// Required landing page checks
if (!data.wordpressPage) {
  throw new Error('Missing wordpressPage');
}

if (!data.landingPageHtml) {
  throw new Error('Missing landingPageHtml');
}

if (!Array.isArray(data.imagePlan)) {
  throw new Error('Missing imagePlan array');
}

if (!data.wordpressApiPayload) {
  data.wordpressApiPayload = {};
}

// Keep payload synced
data.wordpressApiPayload.title = data.wordpressPage.title;
data.wordpressApiPayload.slug = data.wordpressPage.slug;
data.wordpressApiPayload.status = 'draft';
data.wordpressApiPayload.excerpt = data.wordpressPage.excerpt;
data.wordpressApiPayload.content = '';
data.wordpressApiPayload.comment_status = 'closed';
data.wordpressApiPayload.ping_status = 'closed';

// Validate image slots
const html = data.landingPageHtml;

for (const image of data.imagePlan) {
  if (!image.slotId) {
    throw new Error('One imagePlan item is missing slotId');
  }

  const slot = `<!-- IMAGE_SLOT:${image.slotId} -->`;

  if (!html.includes(slot)) {
    throw new Error(`Missing image placeholder in landingPageHtml: ${slot}`);
  }
}

return [
  {
    json: data
  }
];

