function safeNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

function unwrapResponse(raw) {
  let data = raw?.body ?? raw ?? {};

  if (typeof data === 'string') {
    try {
      data = JSON.parse(data);
    } catch (error) {
      data = { rawResponse: data };
    }
  }

  return data;
}

function lastId(resourceName) {
  if (!resourceName || typeof resourceName !== 'string') return 'N/A';
  return resourceName.split('/').pop();
}

function adIdFromAdGroupAdResource(resourceName) {
  if (!resourceName || typeof resourceName !== 'string') return 'N/A';
  const finalPart = resourceName.split('/').pop();
  return finalPart.includes('~') ? finalPart.split('~').pop() : finalPart;
}

// Source nodes
const crmNode = safeNode('CRM Campaign Webhook');
const crm = crmNode.body || crmNode;

const parser =
  safeNode('Parse Claude Landing Page JSON + Build WordPress Payload') ||
  safeNode('Build WordPress Page Payload');

const rankData = safeNode('Parse & Rank Keyword Data');

const wpRaw = safeNode('WordPress REST — Publish Landing Page');
const wp = unwrapResponse(wpRaw);

const campaignRaw = safeNode('Google Ads — Create Search Campaign (PAUSED)');
const campaignResource =
  campaignRaw.results?.[0]?.resourceName ||
  campaignRaw.campaign?.resourceName ||
  campaignRaw.resourceName ||
  '';

const adGroupRaw = safeNode('Google Ads — Create Ad Group');
const adGroupResource =
  adGroupRaw.results?.[0]?.resourceName ||
  adGroupRaw.adGroup?.resourceName ||
  adGroupRaw.resourceName ||
  '';

const rsaRaw = safeNode('Google Ads — Create Responsive Search Ad');
const adResource =
  rsaRaw.results?.[0]?.resourceName ||
  rsaRaw.adGroupAd?.resourceName ||
  rsaRaw.resourceName ||
  '';

const fbRaw = safeNode('Meta Graph — Publish to Facebook Page');
const igRaw = safeNode('Meta Graph — Publish Instagram Post');

const seoData = parser.seoData || {};
const wpPayload = parser.wordpressPayload || {};

const statusParts = [];

if (wp.id) statusParts.push('WordPress page created');
if (campaignResource) statusParts.push('Google Ads campaign created');
if (adGroupResource) statusParts.push('Google Ads ad group created');
if (adResource) statusParts.push('Google Ads responsive search ad created');
if (fbRaw.id) statusParts.push('Facebook post created');
if (igRaw.id) statusParts.push('Instagram post created');

return [
  {
    json: {
      'Timestamp': new Date().toISOString(),
      'Campaign Name': crm.campaignName || 'N/A',
      'Platform': crm.platform || 'N/A',
      'Target Location': crm.targetLocation || 'N/A',
      'Budget': crm.budget || 'N/A',
      'Customer ID': crm.customerId || 'N/A',
      'Ad Account ID': crm.adAccountId || 'N/A',

      'Primary Keyword':
        rankData.primaryKeyword ||
        seoData.primaryKeyword ||
        seoData.wordpressSlug ||
        wpPayload.slug ||
        'N/A',

      'WordPress Page ID': wp.id || 'N/A',
      'WordPress Page URL': wp.link || 'N/A',
      'WordPress Slug': wp.slug || wpPayload.slug || 'N/A',
      'WordPress Status': wp.status || wpPayload.status || 'N/A',

      'SEO Title': seoData.seoTitle || wpPayload.title || 'N/A',
      'Meta Description': seoData.metaDescription || 'N/A',

      'Google Ads Campaign ID': lastId(campaignResource),
      'Google Ads Campaign Resource': campaignResource || 'N/A',
      'Ad Group ID': lastId(adGroupResource),
      'Ad ID': adIdFromAdGroupAdResource(adResource),

      'Meta Facebook Post ID': fbRaw.id || 'N/A',
      'Instagram Post ID': igRaw.id || 'N/A',

      'Automation Status': statusParts.length
        ? statusParts.join(' + ')
        : 'Completed, but no platform result IDs found',

      'Workflow Run ID': $execution.id
    }
  }
];

