    .replace(/\s*```\s*$/i, '')
    .trim();
}

function extractJsonObject(text) {
  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');

  if (firstBrace === -1 || lastBrace === -1 || lastBrace <= firstBrace) {
    throw new Error(
      'No valid JSON object found in Claude response.\nPreview: ' +
      text.slice(0, 500)
    );
  }

  return text.slice(firstBrace, lastBrace + 1);
}

function parseClaudeJson(raw) {
  let text = raw;

  for (let attempt = 1; attempt <= 3; attempt++) {
    if (typeof text !== 'string') {
      return text;
    }

    text = stripCodeFences(text);

    try {
      const parsed = JSON.parse(text);

      if (typeof parsed === 'string') {
        text = parsed;
        continue;
      }

      return parsed;
    } catch (firstError) {
      const extracted = extractJsonObject(text);

      try {
        const parsed = JSON.parse(extracted);

        if (typeof parsed === 'string') {
          text = parsed;
          continue;
        }

        return parsed;
      } catch (secondError) {
        throw new Error(
          'Claude did not return valid JSON: ' +
          secondError.message +
          '\nStart preview: ' +
          extracted.slice(0, 500) +
          '\nEnd preview: ' +
          extracted.slice(-500)
        );
      }
    }
  }

  throw new Error('Unable to parse Claude JSON after multiple attempts.');
}

let raw =
  item.json.text ||
  item.json.output ||
  item.json.response ||
  item.json.data ||
  item.json.content?.[0]?.text ||
  item.json.message?.content ||
  '';

if (Array.isArray(item.json.content)) {
  raw = item.json.content
    .map(part => part.text || part.content || '')
    .join('\n');
}

if (Array.isArray(item.json.message?.content)) {
  raw = item.json.message.content
    .map(part => part.text || part.content || '')
    .join('\n');
}

if (!raw) {
