}

let data = parseClaudeJson(raw);

// Handle accidental array output
if (Array.isArray(data)) {
  if (data.length !== 1) {
    throw new Error('Claude returned an array with multiple items. Expected one landing page object.');
  }

  data = data[0];

  if (data.json) {
    data = data.json;
