}

if (!data.schemaMarkup || typeof data.schemaMarkup !== 'object') {
  throw new Error('Missing schemaMarkup object');
}

if (!data.wordpressApiPayload || typeof data.wordpressApiPayload !== 'object') {
  data.wordpressApiPayload = {};
}

// Remove image fields because this is the no-image version
if (data.imagePlan) {
  delete data.imagePlan;
}

// Remove accidental image placeholders
data.landingPageHtml = data.landingPageHtml
