}

// Required page values
if (!data.wordpressPage.title) {
  throw new Error('Missing wordpressPage.title');
}

if (!data.wordpressPage.excerpt) {
  throw new Error('Missing wordpressPage.excerpt');
}

// Create slug if missing
if (!data.wordpressPage.slug) {
  data.wordpressPage.slug = data.wordpressPage.title;
}

// Normalize slug
data.wordpressPage.slug = String(data.wordpressPage.slug)
  .toLowerCase()
  .trim()
  .replace(/[^a-z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .replace(/-+/g, '-')
  .replace(/^-|-$/g, '');

// Force correct WordPress page settings
data.wordpressPage.postType = 'page';
data.wordpressPage.status = 'draft';

// Ensure arrays exist
data.wordpressPage.secondaryKeywords = Array.isArray(data.wordpressPage.secondaryKeywords)
