data.wordpressPage.categories = Array.isArray(data.wordpressPage.categories)
  ? data.wordpressPage.categories
  : [];

data.schemaMarkup.keywords = Array.isArray(data.schemaMarkup.keywords)
  ? data.schemaMarkup.keywords
  : [];

// Keep original wordpressApiPayload synced
// Important: content remains empty because your original prompt requires it
